// Calculate cutoff: 7 days ago (start of previous week)
const oneWeekAgo = new Date();
oneWeekAgo.setDate(oneWeekAgo.getDate() - 7);

// n8n API returns { data: [...executions] }
const executions = $input.first().json.data || [];

// Keep only executions older than 7 days
const oldExecutions = executions.filter(e => {
  const startedAt = new Date(e.startedAt);
  return startedAt < oneWeekAgo;
});

if (oldExecutions.length === 0) {
  // Return a no-op item so workflow doesn't error
  return [{ json: { message: 'No old executions to delete.', count: 0 } }];
}

// Return each execution ID as a separate item for the DELETE node
return oldExecutions.map(e => ({
  json: {
    id: e.id,
    workflowName: e.workflowData?.name || 'Unknown',
    startedAt: e.startedAt,
    status: e.status
  }
}));

// Log skipped (no executions to delete)
console.log('No old executions found. Nothing deleted.');
return [{ json: { skipped: true, message: $input.first().json.message } }];
